import{_ as a,o as i,c as s,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Individual Practice","description":"","frontmatter":{},"headers":[],"relativePath":"practice/individual-practice.md","filePath":"practice/individual-practice.md"}'),n={name:"practice/individual-practice.md"};function o(r,e,c,l,d,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="individual-practice" tabindex="-1">Individual Practice <a class="header-anchor" href="#individual-practice" aria-label="Permalink to &quot;Individual Practice&quot;">​</a></h1><p>Individual Practice sessions focus on one player. They include access to the Mechanics Assessment logger in addition to the standard four loggers.</p><h2 id="when-to-use-individual-practice" tabindex="-1">When to Use Individual Practice <a class="header-anchor" href="#when-to-use-individual-practice" aria-label="Permalink to &quot;When to Use Individual Practice&quot;">​</a></h2><ul><li>One-on-one skill sessions between coach and player</li><li>Pre-game warm-up pitching evaluation</li><li>Post-game review of technique</li><li>Mechanics assessments (required for mechanics analytics)</li></ul><h2 id="starting-an-individual-practice-session" tabindex="-1">Starting an Individual Practice Session <a class="header-anchor" href="#starting-an-individual-practice-session" aria-label="Permalink to &quot;Starting an Individual Practice Session&quot;">​</a></h2><ol><li>From the dashboard tap <strong>Log Practice Data</strong></li><li>Select <strong>Individual Practice</strong></li><li>Select the player from your roster</li><li>Tap <strong>Start Session</strong></li></ol><p>All loggers now default to the selected player. You can still change the player in any logger — useful if you assess multiple players back to back in the same session.</p><h2 id="mechanics-assessments-in-individual-practice" tabindex="-1">Mechanics Assessments in Individual Practice <a class="header-anchor" href="#mechanics-assessments-in-individual-practice" aria-label="Permalink to &quot;Mechanics Assessments in Individual Practice&quot;">​</a></h2><p>The <strong>Mechanics Assessment</strong> option appears in the Practice Hub when in Individual Practice mode. Tap it to open the assessment logger for the selected player&#39;s sport and position.</p><p>See <a href="/practice/mechanics-assessments.html">Mechanics Assessments</a> for complete assessment instructions.</p><h2 id="post-session-notes" tabindex="-1">Post-Session Notes <a class="header-anchor" href="#post-session-notes" aria-label="Permalink to &quot;Post-Session Notes&quot;">​</a></h2><p>At the end of an Individual Practice session the app prompts you to add session notes. These notes connect to the player&#39;s Coach Notes history. Use this prompt to capture observations while they are fresh — it takes less than a minute and creates a permanent record of what was observed and worked on.</p>',12)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
